#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long A, B, C;
        scanf("%lld %lld %lld", &A, &B, &C);
        long long total = A + B + C;
        long long mn = A;
        if (B < mn) mn = B;
        if (C < mn) mn = C;
        printf("%lld\n", total - mn);
    }
    return 0;
}

